#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;

using PVZEngine.Definitions;
using PVZEngine.Entities;

using UnityEngine;

namespace MVZ2.GameContent.Entities
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.randomChangeVelocity)]
    public class RandomChangeVelocityBehaviour : EntityBehaviourDefinition
    {
        public RandomChangeVelocityBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            var accelerationMax = entity.GetProperty<Vector3>(PROP_ACCELERATION_MAX);
            var accelerationMin = entity.GetProperty<Vector3>(PROP_ACCELERATION_MIN);
            var rng = entity.RNG;
            var x = rng.NextFloat() * (accelerationMax.x - accelerationMin.x) + accelerationMin.x;
            var y = rng.NextFloat() * (accelerationMax.y - accelerationMin.y) + accelerationMin.y;
            var z = rng.NextFloat() * (accelerationMax.z - accelerationMin.z) + accelerationMin.z;
            var acceleration = entity.GetProperty<Vector3>(PROP_ACCELERATION);
            acceleration += new Vector3(x, y, z);
            entity.SetProperty(PROP_ACCELERATION, acceleration);

            entity.Velocity += acceleration;
        }
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_ACCELERATION = new VanillaEntityPropertyMeta<Vector3>("acceleration");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_ACCELERATION_MAX = new VanillaEntityPropertyMeta<Vector3>("acceleration_max", Vector3.one * 0.01f);
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_ACCELERATION_MIN = new VanillaEntityPropertyMeta<Vector3>("acceleration_min", Vector3.one * -0.01f);
    }
}
